class Solution:
    def makeSimilar(self, nums, target):
        ne = sorted(x for x in nums if x % 2 == 0)
        no = sorted(x for x in nums if x % 2 == 1)
        te = sorted(x for x in target if x % 2 == 0)
        to = sorted(x for x in target if x % 2 == 1)
        ops = 0
        for a, b in zip(ne, te):
            if b > a:
                ops += (b - a) // 2
        for a, b in zip(no, to):
            if b > a:
                ops += (b - a) // 2
        return ops

