class Solution:
    def makeSimilar(self, nums, target):
        a = sorted(nums, key=lambda x: (x % 2, x))
        b = sorted(target, key=lambda x: (x % 2, x))
        total = sum(y - x for x, y in zip(a, b) if y > x)
        return total // 2

