var makeSimilar = function(nums, target) {
    const cmp = (x, y) => (x % 2) - (y % 2) || x - y;
    const a = [...nums].sort(cmp);
    const b = [...target].sort(cmp);
    let total = 0;
    for (let i = 0; i < a.length; i++) {
        if (b[i] > a[i]) total += b[i] - a[i];
    }
    return Math.floor(total / 2);
};
